class Solution:
    def chalkReplacer(self, chalk, k):
        # Independent: reduce by repeatedly subtracting whole-round sums in bulk, then linear scan.
        total = sum(chalk)
        k %= total
        for i, c in enumerate(chalk):
            if k < c:
                return i
            k -= c
        return 0

