var chalkReplacer = function(chalk, k) {
    let total = 0;
    for (const c of chalk) total += c;
    k %= total;
    for (let i = 0; i < chalk.length; i++) {
        if (k < chalk[i]) return i;
        k -= chalk[i];
    }
    return chalk.length - 1;
};
